import{_ as a,o as t,c as r,a6 as o}from"./chunks/framework.CPCSkjM7.js";const u=JSON.parse('{"title":"Index of Projects","description":"","frontmatter":{},"headers":[],"relativePath":"projects/index.md","filePath":"projects/index.md","lastUpdated":1782301405000}'),n={name:"projects/index.md"};function s(i,e,l,h,c,d){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="index-of-projects" tabindex="-1">Index of Projects <a class="header-anchor" href="#index-of-projects" aria-label="Permalink to “Index of Projects”">​</a></h1><h2 id="matthew-wempe-2d-rpg-video-game" tabindex="-1">Matthew Wempe - 2D RPG Video Game <a class="header-anchor" href="#matthew-wempe-2d-rpg-video-game" aria-label="Permalink to “Matthew Wempe - 2D RPG Video Game”">​</a></h2><ul><li><a href="https://github.com/user-attachments/files/29263315/2D.RPG.Video.Game.-.Matthew.Wempe.pdf?raw=true" target="_blank" rel="noreferrer"><strong>Documentation</strong></a></li><li><strong>Abstract</strong>: &quot;This project is a top down Two-Dimensional (2D) Role-playing (RP) dungeon crawler game. The player takes control of a mage who traverses through dungeon levels while encountering challenging enemies and bosses. Along their journey, players can expect to collect gold and gain experience which can be used to level up their health and skills. For players to advance to the next dungeon level, they will have to complete certain objectives. These objectives vary from defeating a certain number of enemies to solving puzzles.&quot;</li></ul><h2 id="jonah-king-3-d-space-shooter" tabindex="-1">Jonah King - 3-D Space Shooter <a class="header-anchor" href="#jonah-king-3-d-space-shooter" aria-label="Permalink to “Jonah King - 3-D Space Shooter”">​</a></h2><ul><li><a href="https://github.com/user-attachments/files/29263679/3-D.Space.Shooter.-.Jonah.King.pdf" target="_blank" rel="noreferrer"><strong>Documentation</strong></a></li><li><strong>Abstract</strong>: &quot;In order to make the greatness of my senior project happen I used Unity, Visual Studio, and C#. Unity is a game development software that uses a sophisticated UI to make programming for games a much more manageable task. It makes it easier to hookup different prefabs to code Scripts and then develop scenes that a user can play out in a game. I also used Unities Asset store to get all of my models and sound bites that I used in the project. I chose C# because Unities scripts are meant to be constructed using C# and defaults to Visual studio which automagically connects the code you construct to the physical game.&quot;</li></ul><h2 id="andal-tibayan-3d-video-conference-parts-1-and-2" tabindex="-1">Andal &amp; Tibayan - 3D Video Conference Parts 1 and 2 <a class="header-anchor" href="#andal-tibayan-3d-video-conference-parts-1-and-2" aria-label="Permalink to “Andal &amp; Tibayan - 3D Video Conference Parts 1 and 2”">​</a></h2><ul><li><a href="https://github.com/user-attachments/files/29290509/3D.Video.Conference.Part.1.-.Andal.Tibayan.pdf" target="_blank" rel="noreferrer"><strong>Documentation Part 1</strong></a></li><li><a href="https://github.com/user-attachments/files/29290534/3D.Video.Conference.Part.2.-.Andal.Tibayan.pdf" target="_blank" rel="noreferrer"><strong>Documentation Part 2</strong></a></li><li><strong>Abstract</strong>: &quot;3D Video Conferencing is a program designed to utilize two DirectShow compatible web cameras to create a more &quot;immersive&quot; and 3D experience for the party participating in a video conference. The frames from each of the web cameras rapidly interleaving are outputted to the user&#39;s screen. Using eDimensional&#39;s LCD (Liquid Crystal Display) shutter glasses, the interleaving frames create the illusion of 3D.</li></ul><h2 id="austin-richards-a-tour-of-cryptography" tabindex="-1">Austin Richards - A Tour of Cryptography <a class="header-anchor" href="#austin-richards-a-tour-of-cryptography" aria-label="Permalink to “Austin Richards - A Tour of Cryptography”">​</a></h2><ul><li><a href="https://github.com/user-attachments/files/29290746/A.Tour.of.Cryptography.-.Austin.Richards.pdf" target="_blank" rel="noreferrer"><strong>Documentation</strong></a></li></ul><h2 id="christopher-corbett-analysis-and-design" tabindex="-1">Christopher Corbett - Analysis and Design <a class="header-anchor" href="#christopher-corbett-analysis-and-design" aria-label="Permalink to “Christopher Corbett - Analysis and Design”">​</a></h2><ul><li><a href="https://github.com/user-attachments/files/29290790/Analysis.and.Design.-.Christopher.Corbett.pdf" target="_blank" rel="noreferrer"><strong>Documentation</strong></a></li></ul>',11)])])}const g=a(n,[["render",s]]);export{u as __pageData,g as default};
